class Solution:
    def solve(self, s: str, k: int) -> int:
        length = len(s)
        max_len = 0
        max_repeats = 0
        temp = s[:-1]
        for i in range(1, k):
            if temp[i:] == temp[:i]:
                max_repeats = max(max_repeats, i)
                max_len = max(max_len, i * 2 + max_repeats)
        return max_len

    def main(self):
        s = input()
        n = int(input())
        print(self.solve(s, n))

if __name__ == '__main__':
    solution = Solution()
    solution.main()

