class Solution{
public:
int solve(string s, int k){
	int length = s.size(), max_len = 0, max_repeats = 0;
	string temp = s.substr(0, s.size() - 1);
	for (int i = 1; i < k; i++){
		if (temp.substr(i) == temp.substr(0, i)){
			max_repeats = max(max_repeats, i);
			max_len = max(max_len, i * 2 + max_repeats);
		}
	}
	return max_len;
}
};
